import scala.collection.mutable

def gcd(a: Long, b: Long): Long = {
    var (x, y) = (math.abs(a), math.abs(b))
    while (y != 0) {
        val temp = y
        y = x % y
        x = temp
    }
    x
}

def solve(points: Array[Array[Long]]): Long = {
    val n = points.length
    val groups = mutable.HashMap.empty[(Long, Long), mutable.ArrayBuffer[(Int, Int)]]

    for (i <- 0 until n; j <- i + 1 until n) {
        val (x1, y1) = (points(i)(0), points(i)(1))
        val (x2, y2) = (points(j)(0), points(j)(1))
        val dx = x2 - x1
        val dy = y2 - y1

        if (dx == 0 && dy == 0) {
            // Skip if same point, though distinct points ensure this won't happen
        } else {
            val g = gcd(dx, dy)
            var dx0 = dx / g
            var dy0 = dy / g

            if (dy0 < 0) {
                dx0 = -dx0
                dy0 = -dy0
            } else if (dy0 == 0 && dx0 < 0) {
                dx0 = -dx0
            }

            val key = (dx0, dy0)
            groups.getOrElseUpdate(key, mutable.ArrayBuffer.empty) += ((i, j))
        }
    }

    var total_raw = 0L

    for ((_, buf) <- groups) {
        val m = buf.size
        val totalPairs = m.toLong * (m - 1) / 2
        val deg = mutable.HashMap.empty[Int, Int]

        for ((i, j) <- buf) {
            deg(i) = deg.getOrElse(i, 0) + 1
            deg(j) = deg.getOrElse(j, 0) + 1
        }

        var overlap = 0L
        for (d_value <- deg.values) {
            if (d_value >= 2) {
                overlap += d_value.toLong * (d_value - 1) / 2
            }
        }

        total_raw += (totalPairs - overlap)
    }

    val center_map = mutable.HashMap.empty[(Long, Long), Int]
    for (i <- 0 until n; j <- i + 1 until n) {
        val (x1, y1) = (points(i)(0), points(i)(1))
        val (x2, y2) = (points(j)(0), points(j)(1))
        val midx = x1 + x2
        val midy = y1 + y2
        center_map((midx, midy)) = center_map.getOrElse((midx, midy), 0) + 1
    }

    var total_center = 0L
    for (count <- center_map.values) {
        total_center += count.toLong * (count - 1) / 2
    }

    total_raw - total_center
}
```

### Explanation
1. **Slope Grouping**: The algorithm starts by iterating over all pairs of distinct points. For each pair, it computes the direction vector (dx, dy) and normalizes it to a canonical form to handle different representations of the same slope. This ensures that parallel segments are grouped together.
2. **Disjoint Pairs Counting**: For each slope group, the algorithm calculates the number of valid segment pairs that do not share any vertices. This involves:
   - Computing the total possible pairs of segments in the group.
   - Subtracting pairs that share vertices (which cannot form a quadrilateral).
3. **Parallelogram Adjustment**: The algorithm accounts for parallelograms by grouping segments that share a common midpoint. Each parallelogram is identified by two segments (diagonals) sharing the same midpoint. The count of such parallelograms is subtracted from the total trapezoids to avoid double-counting.
4. **Result Calculation**: The final result is obtained by subtracting the number of parallelograms from the total trapezoids identified, ensuring each trapezoid is counted exactly once.

This approach efficiently counts trapezoids by leveraging slope grouping and midpoint checks, ensuring optimal performance even for larger input sizes.

